import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Encontrar Mods Confiables","description":"Una guía sobre como encontrar mods de Fabric usando fuentes confiables.","frontmatter":{"title":"Encontrar Mods Confiables","description":"Una guía sobre como encontrar mods de Fabric usando fuentes confiables.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.4/players/finding-mods.md","filePath":"versions/1.21.4/translated/es_es/players/finding-mods.md","lastUpdated":1760721669000}`);var a={name:`es_es/1.21.4/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Encontrar Mods Confiables <a class="header-anchor" href="#h1" aria-label="Permalink to “Encontrar Mods Confiables”">​</a></h1><p>En primer lugar, el término &quot;confiable&quot; es subjetivo, así que siempre usa tu propio juicio y sentido común a la hora de descargar mods. Sin embargo, hay algunas cosas que puedes hacer para encontrar mods confiables.</p><h2 id="_1-usa-una-fuente-conocida-por-su-confiabilidad-y-seguridad" tabindex="-1">1. Usa una fuente conocida por su confiabilidad y seguridad <a class="header-anchor" href="#_1-usa-una-fuente-conocida-por-su-confiabilidad-y-seguridad" aria-label="Permalink to “1. Usa una fuente conocida por su confiabilidad y seguridad”">​</a></h2><p>La mayoría de desarrolladores publican sus mods en <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> y <a href="https://www.curseforge.com/minecraft/search?page=1&amp;pageSize=20&amp;sortType=1&amp;class=mc-mods&amp;gameFlavorsIds=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Estas páginas web verifican los mods hacen lo que dicen hacer, y que no contengan código malicioso. También puedes reportar mods maliciosos en esas páginas web, y tomarán acción relativamente rápida.</p><h2 id="_2-¡verifica-con-otros" tabindex="-1">2. ¡Verifica con otros! <a class="header-anchor" href="#_2-¡verifica-con-otros" aria-label="Permalink to “2. ¡Verifica con otros!”">​</a></h2><p>Si descargas un mod desde una fuente que no es conocida por ser segura, puedes verificar con otros para ver si ellos han descargado el mod antes desde la misma fuente que tu, y verificar si han tenido problemas con ella.</p><p>Si no estás seguro, eres bienvenido a consultar en el servidor de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a>, en el canal de <code>#player-support</code>.</p><h2 id="_3-¡evita-sitios-con-malware-comunes" tabindex="-1">3. ¡Evita sitios con malware comunes! <a class="header-anchor" href="#_3-¡evita-sitios-con-malware-comunes" aria-label="Permalink to “3. ¡Evita sitios con malware comunes!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Identificar páginas web con malware no es algo obvio para todos. Si no estás seguro, deberías consultar por opiniones de otros o evitar el sitio completamente y solamente usar fuentes seguras, como Modrinth y CurseForge.</p></div><p>Hay muchas páginas web que dicen tener mods para Minecraft, pero en realidad solo contienen malware. Debes evitar estos sitios a toda costa.</p><p>Puedes usar software de antivirus y páginas web como <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> o <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> para verificar los mods descargados. Sin embargo, no te bases completamente en esos métodos, ya que pueden producir resultados incorrectos.</p><p>Para reiterar, eres bienvenido a consultar en el servidor de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a>, en el canal de <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};